INSERT INTO `features` (`id`, `title`, `description`, `icon`, `sort_order`) VALUES ('1', 'Tradición', 'Creemos que la tradición es el alma de cada receta que sale del horno.', '/images/editada-02.webp', '1');
INSERT INTO `features` (`id`, `title`, `description`, `icon`, `sort_order`) VALUES ('2', 'Sin Atajos', 'Cero procesos industriales. Solo ingredientes reales y paciencia.', '/images/editada-23.webp', '2');
INSERT INTO `features` (`id`, `title`, `description`, `icon`, `sort_order`) VALUES ('3', '100% Manos Vecinas', 'Amasamos, horneamos y servimos cada día con orgullo local.', '/images/editada-32.webp', '3');
INSERT INTO `features` (`id`, `title`, `description`, `icon`, `sort_order`) VALUES ('4', 'Café de Especialidad', 'Seleccionamos granos de origen y los tratamos con respeto.', '/images/editada-38.webp', '4');
