INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('67', 'Almojábena', '1.05', 'pasteleria', NULL, 'Un dulce clásico para acompañar tu café. Nuestra almojábena tiene masa tierna, borde dorado y el punto justo de azúcar. Una elección sencilla y apetecible para cualquier mañana.', '/images/products/almojabena.webp', '[\"Harina de trigo\", \"aceite de girasol\", \"agua\", \"huevo\", \"azúcar.\"]', '[\"Gluten\", \"Huevo\", \"(Trazas posibles: crustáceos, cacahuetes, frutos de cáscara).\"]', '0', '1', '1', 'Almojábena dulce horneada a diario para el desayuno en Amalis Cafetería.', 'Almojábena - Dulce de Pastelería', 'Pídela ligeramente templada y acompáñala con un café con leche para disfrutar mejor su textura.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('68', 'Pizza de Jamón York y Queso', '2.55', 'bolleria_salada', NULL, 'Una opción salada que siempre funciona. Base crujiente, salsa de tomate, jamón york y queso mozzarella fundido en un bocado cómodo para almorzar o merendar.', '/images/products/Pizza-York.webp', '[\"Harina de trigo\", \"aceite de oliva\", \"tomate frito\", \"auténtico queso mozzarella y jamón york extra.\"]', '[\"Gluten (Trigo)\", \"Leche\", \"Soja\", \"(Puede contener trazas de huevo).\"]', '0', '1', '2', 'Crujiente pizza de jamón york y queso mozzarella fundido, un clásico infalible en Amalis Cafetería.', 'Pizza de Jamón York y Queso - Sabor Clásico', 'Pídenos que te la calentemos un poco para que la mozzarella se funda mejor. Queda muy bien con una bebida refrescante.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('69', 'Bizcocho de Canela', '14.70', 'bolleria_dulce', NULL, 'Bizcocho de canela con miga esponjosa y aroma casero, rematado con azúcar perlado. Su formato grande va muy bien para compartir en casa o en una merienda.', '/images/products/Bizcocho-Canela.webp', '[\"Harina de trigo\", \"azúcar\", \"leche\", \"huevo\", \"aceite de girasol\", \"nuestra aromática canela y un irresistible toque de azúcar perlado.\"]', '[\"Gluten (Trigo)\", \"Leche\", \"Huevo\"]', '0', '1', '3', 'Esponjoso bizcocho de canela entero con toques de azúcar perlado, ideal para compartir en Amalis Cafetería.', 'Bizcocho Especial de Canela - Formato Familiar', 'Córtalo en rebanadas y disfrútalo con chocolate caliente o café con leche espumoso. La canela se aprecia especialmente bien en caliente.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('70', 'Bizcocho de Naranja', '16.00', 'bolleria_dulce', NULL, 'Bizcocho de naranja con miga esponjosa, toque cítrico y discos de naranja confitada. El azúcar perlado aporta contraste y su formato grande lo convierte en una muy buena opción para compartir.', '/images/products/Bizcocho-Naranja.webp', '[\"Harina de trigo\", \"azúcar\", \"leche\", \"huevo\", \"aceite de girasol\", \"irresistibles discos de naranja confitada y crujiente azúcar perlado.\"]', '[\"Gluten (Trigo)\", \"Leche\", \"Huevo\", \"Sulfitos\"]', '0', '1', '4', 'Esponjoso bizcocho de naranja entero decorado con discos de naranja y azúcar perlado en Amalis Cafetería.', 'Bizcocho Extra Esponjoso de Naranja - Gran Formato', 'Disfrútalo con café solo, té o una infusión de frutas. Si lo sirves templado, su aroma cítrico se aprecia todavía más.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('71', 'Bizcocho de Pepitas de Chocolate', '18.00', 'bolleria_dulce', NULL, 'Bizcocho de chocolate con miga jugosa, sabor intenso a cacao y abundantes pepitas de chocolate en cada porción. Un formato grande para compartir o disfrutar durante varios días.', '/images/products/Bizcocho-Chocolate-Pepitas.webp', '[\"Harina de trigo\", \"azúcar\", \"leche\", \"huevo\", \"cacao desgrasado en polvo\", \"aceite de girasol y abundantes y deliciosas pepitas de chocolate.\"]', '[\"Gluten (Trigo)\", \"Leche\", \"Huevo\"]', '0', '1', '5', 'Bizcocho de chocolate entero con pepitas de chocolate en Amalis Cafetería.', 'Bizcocho de Chocolate con Pepitas - Especial para Golosos', 'Queda muy bien con leche fría o con café. Si lo calientas ligeramente, las pepitas se funden y la textura gana jugosidad.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('72', 'Bizcocho de Piña', '14.70', 'bolleria_dulce', NULL, 'Bizcocho de piña con miga tierna y jugosa gracias al jugo natural, rematado con rodajas de fruta y azúcar perlado. Una opción diferente y fresca para compartir.', '/images/products/Bizcocho.webp', '[\"Harina de trigo\", \"azúcar\", \"leche\", \"huevo\", \"aceite de girasol\", \"jugo natural y rodajas de piña bañadas con nuestro azúcar perlado.\"]', '[\"Gluten (Trigo)\", \"Leche\", \"Huevo\"]', '0', '1', '6', 'Jugoso bizcocho de piña entero con rodajas de fruta tropical en Amalis Cafetería.', 'Bizcocho Tropical de Piña - Ideal para Compartir', 'Pruébalo con una infusión fría o un té helado en días cálidos. Su jugosidad lo hace agradable a cualquier hora.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('73', 'Bizcocho de Pistacho', '26.00', 'bolleria_dulce', NULL, 'Nuestro bizcocho de pistacho 100% tostado destaca por su sabor intenso y elegante. La miga tierna y el aroma tostado lo convierten en una opción muy buena para momentos especiales.', '/images/products/Bizcocho-Pistacho.webp', '[\"Harina de trigo\", \"azúcar\", \"leche\", \"huevo\", \"aceite de girasol\", \"deliciosa pasta de 100% pistacho tostado y nuestro toque de azúcar perlado.\"]', '[\"Gluten (Trigo)\", \"Leche\", \"Huevo\", \"Frutos de cáscara (Pistacho)\"]', '0', '1', '7', 'Bizcocho de pistacho 100% tostado de formato entero en Amalis Cafetería.', 'Bizcocho Premium de Pistacho - Sabor Intenso Tostado', 'Acompáñalo con un café de especialidad o un espresso. El toque tostado del pistacho combina muy bien con el café.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('74', 'Bizcocho de Zanahoria', '15.70', 'bolleria_dulce', NULL, 'Bizcocho de zanahoria con miga jugosa, dulzor suave y un toque de azúcar perlado. Un dulce reconfortante para quienes buscan sabores clásicos y equilibrados.', '/images/products/Bizcocho.webp', '[\"Harina de trigo\", \"azúcar\", \"leche\", \"huevo\", \"aceite de girasol\", \"zanahoria fresca rallada y crujiente azúcar perlado.\"]', '[\"Gluten (Trigo)\", \"Leche\", \"Huevo\"]', '0', '1', '8', 'Bizcocho de zanahoria entero, esponjoso y horneado al estilo tradicional en Amalis Cafetería.', 'Bizcocho Tradicional de Zanahoria - Sabor Casero', 'Por su jugosidad, combina muy bien con café caliente o con un zumo natural en el desayuno. Una buena opción si buscas un dulce más suave.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('75', 'Borracho', '2.50', 'pasteleria', NULL, 'Dulce tradicional de almendra molida, ralladura de naranja y jarabe de canela. Su textura húmeda y melosa lo convierte en una opción muy agradable para la sobremesa.', '/images/products/Pastel-Borracho.webp', '[\"Harina de trigo\", \"azúcar\", \"huevo y yema de gallina\", \"almendra molida\", \"raspadura de naranja y nuestro característico baño de jarabe de canela.\"]', '[\"Gluten (Trigo)\", \"Huevo\", \"Frutos de cáscara (Almendra)\"]', '0', '1', '9', 'Dulce Borracho tradicional bañado en almíbar de canela con un toque de naranja en Amalis Cafetería.', 'Dulce Borracho - Jugosidad Tradicional', 'Queda muy bien con café solo o cortado. El amargor del café equilibra su dulzor amibarado.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('76', 'Coca de Jamón York y Queso', '2.30', 'bolleria_salada', NULL, 'Coca salada de masa rústica con aceite de oliva, mollitas y jamón york con queso fundido. Una opción sabrosa para recargar energías a media mañana.', '/images/products/coca-jamon-york-y-queso.webp', '[\"Harina de trigo\", \"agua y manteca de cerdo en base y mollitas tradicionales de masa panadera horneada\", \"aceite de oliva (virgen y orujo)\", \"exquisito jamón york y queso fundido de leche pasteurizada.\"]', '[\"Gluten (Trigo)\", \"Leche\", \"Soja\", \"(Puede contener trazas de pescado).\"]', '0', '1', '10', 'Tradicional coca salada con mollitas, jamón york y queso fundido horneada en Amalis Cafetería.', 'Coca de Jamón York y Queso - Clásico Almuerzo', 'Si pides que te la templemos ligeramente, notarás cómo el queso se funde con las mollitas crujientes. Queda muy bien con una cerveza bien fría o un refresco.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('77', 'Coca de Verdura', '2.30', 'bolleria_salada', NULL, 'Coca de verdura sobre masa rústica con aceite de oliva y una cobertura de pimiento rojo, pimiento verde y cebolla pochada. Una opción sabrosa y más ligera para almuerzo o merienda.', '/images/products/Pizza-Verduras.webp', '[\"Harina de trigo\", \"agua y manteca de cerdo en masa tradicional con aceite de oliva\", \"cubierta con una generosa mezcla pochada de pimiento rojo\", \"pimiento verde y cebolla dulce.\"]', '[\"Gluten (Trigo)\", \"(Puede contener trazas de pescado).\"]', '0', '1', '11', 'Coca salada tradicional cubierta de tiernas verduras horneadas (pimientos y cebolla) en Amalis Cafetería.', 'Coca de Verdura - Sabrosa y Tradicional', 'Pruébala templada. El calor realza el aroma de la masa y la jugosidad de las verduras.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('78', 'Coca Rellena', '2.30', 'bolleria_salada', NULL, 'Hojaldre crujiente con relleno de pisto de verduras y atún claro, jugoso y con sabor equilibrado. Una opción salada que funciona bien cuando necesitas algo completo.', '/images/products/Coca-Pisto.webp', '[\"Harina de trigo\", \"agua y margarina en nuestro hojaldre crujiente horneado\", \"relleno de una rica compota de hortalizas (tomate\", \"cebolla\", \"berenjena\", \"calabacín\", \"pimientos) y atún claro en aceite de girasol.\"]', '[\"Gluten (Trigo)\", \"Pescado\", \"Soja\", \"Huevo\", \"(Posibles trazas de: cacahuetes, leche, frutos de cáscara).\"]', '0', '1', '12', 'Coca de hojaldre rellena de pisto de verduras y atún claro en Amalis Cafetería.', 'Coca Rellena de Pisto y Atún - Capricho Salado', 'Muy buena para un almuerzo completo. El contraste entre el hojaldre dorado y el pisto jugoso funciona muy bien para tomar aquí o para llevar con un refresco.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('79', 'Coca Salada', '2.30', 'bolleria_salada', NULL, 'Una coca salada muy ligada al almuerzo tradicional. La masa con aceite de oliva y un toque de leche se hornea hasta quedar crujiente, y la sardina salada aporta el punto de carácter.', '/images/products/Coca-Sardina.webp', '[\"Harina de trigo\", \"agua y manteca de cerdo en masa rústica de panadería con aceite de oliva (virgen y orujo)\", \"leche\", \"y el toque tradicional valenciano inconfundible de la sardina salada.\"]', '[\"Gluten (Trigo)\", \"Leche\", \"Pescado\"]', '0', '1', '13', 'Tradicional coca salada valenciana con sardina salada en panadería Amalis Cafetería.', 'Coca Salada con Sardina - Receta Tradicional', 'Una opción clásica para almuerzo. Acompáñala con una bebida fría si te gusta el contraste con la sardina salada.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('80', 'Croissant', '1.65', 'bolleria_dulce', NULL, 'Croissant clásico de hojaldre, crujiente por fuera y tierno por dentro, con miga alveolada y dorado uniforme. Una pieza sencilla que encaja en desayuno, almuerzo o merienda.', '/images/products/Croissant-Mantequilla.webp', '[\"Masa hojaldrada tradicional elaborada con harina de trigo y levadura\", \"horneada al punto para conseguir esa corteza dorada y miga tierna inconfundible.\"]', '[\"Gluten (Trigo)\", \"(Posibles trazas de: Soja y Frutos de cáscara).\"]', '0', '1', '14', 'Croissant clásico horneado y hojaldrado, tierno por dentro y dorado por fuera, en Amalis Cafetería.', 'Croissant Clásico - El Rey del Desayuno', 'Va muy bien con café con leche. Si lo prefieres salado, puedes pedirlo a la plancha con jamón york y queso, o con mantequilla y mermelada.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('81', 'Mini Empanadilla de Atún y Huevo', '1.05', 'bolleria_salada', NULL, 'Mini empanadilla de masa fina y dorada con relleno de atún y huevo. Un bocado salado práctico, sabroso y económico para cualquier hora.', '/images/products/mini-empanadilla-atun-y-huevo-2.webp', '[\"Masa fina de harina de trigo\", \"rellena de un sofrito casero tradicional\", \"abundante atún claro y tiernos trozos de huevo.\"]', '[\"Gluten (Trigo)\", \"Pescado\", \"Leche\", \"Soja\", \"Huevo\", \"(Posibles trazas de: crustáceos\", \"cacahuetes\", \"frutos de cáscara).\"]', '0', '1', '15', 'Mini empanadilla salada dorada y hojaldrada, rellena de atún claro y huevo en Amalis Cafetería.', 'Mini Empanadilla de Atún y Huevo - Bocado Tradicional', 'Pide un par y tómalas ligeramente templadas junto a un refresco. Con un toque de calor el relleno recupera jugosidad.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('82', 'Mini Empanadilla de Atún y Cebolla', '1.05', 'bolleria_salada', NULL, 'Masa fina horneada con relleno de atún claro y cebolla frita, con un punto dulce muy agradable. Un bocado sabroso para picar o acompañar una bebida.', '/images/products/mini-empanadilla-atun-y-huevo-2-2.webp', '[\"Masa fina de harina de trigo\", \"rellena del clásico sofrito\", \"atún claro extra y un delicioso contraste de cebolla frita.\"]', '[\"Gluten (Trigo)\", \"Pescado\", \"Leche\", \"Soja\", \"Huevo\", \"(Posibles trazas de: crustáceos\", \"cacahuetes\", \"frutos de cáscara).\"]', '0', '1', '16', 'Mini empanadilla salada dorada rellena de sofrito de atún y cebolla dulce frita en Amalis Cafetería.', 'Mini Empanadilla de Atún y Cebolla - Sabor Extra', 'La cebolla frita aporta un punto dulce que contrasta muy bien con una bebida amarga, como un vermut o una cerveza bien fría.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('83', 'Empanadilla de Pisto y Atún', '1.55', 'bolleria_salada', NULL, 'Empanadilla clásica de buen tamaño, con masa tierna y relleno de pisto de verduras con atún. Muy buena para almorzar o merendar cuando buscas algo salado y completo.', '/images/products/Empanada-Pisto.webp', '[\"Masa tradicional a base de harina de trigo\", \"agua y aceite de girasol\", \"rellena abundantemente de una compota de hortalizas (tomate\", \"berenjena\", \"calabacín\", \"pimientos) y atún claro.\"]', '[\"Gluten (Trigo)\", \"Pescado\", \"Soja\", \"(Posibles trazas de: crustáceos, huevo, leche, cacahuetes, frutos de cáscara).\"]', '0', '1', '17', 'Empanadilla salada grande rellena de pisto tradicional de verduras y atún claro, horneada en Amalis Cafetería.', 'Empanadilla de Pisto y Atún - Sabor Casero', 'Una opción práctica para media mañana o media tarde. Si puedes, pídela templada para potenciar el sabor del sofrito.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('84', 'Ensaimada', '1.60', 'bolleria_dulce', NULL, 'Ensaimada clásica, ligera y esponjosa, con forma en espiral y dulzor suave. Su miga muy alveolada y el toque de azúcar la hacen una opción tradicional para desayunar.', '/images/products/Ensaimada.webp', '[\"Harina de trigo\", \"manteca de cerdo\", \"agua\", \"azúcar\", \"levadura\", \"huevo y margarina\", \"formando su característica masa hojaldrada dulce.\"]', '[\"Gluten (Trigo)\", \"Huevo\", \"(Posibles trazas de: soja, leche, sésamo).\"]', '0', '1', '18', 'Ensaimada clásica tradicional, esponjosa y espolvoreada con azúcar en Amalis Cafetería.', 'Ensaimada Clásica - Esponjosidad Tradicional', 'Va muy bien con café con leche para el desayuno, cortándola a pellizcos y mojando. Si te gusta más golosa, puedes pedirla con mantequilla y mermelada.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('85', 'Media Lunas', '2.70', 'pasteleria', NULL, 'Bocado de repostería fina con almendra, ralladura de naranja y jarabe de canela. Su textura tierna y jugosa la convierte en una muy buena opción para merienda o sobremesa.', '/images/products/Pastel-MediaLuna.webp', '[\"Harina de trigo\", \"azúcar\", \"huevo y yemas de gallina\", \"almendra molida\", \"raspadura de naranja y todo delicadamente bañado en jarabe de canela.\"]', '[\"Gluten (Trigo)\", \"Huevo\", \"Frutos de cáscara (Almendra)\"]', '0', '0', '19', 'Media luna dulce y jugosa elaborada con almendra, naranja y almíbar de canela en Amalis Cafetería.', 'Media Lunas de Almendra - Repostería Fina', 'Van muy bien como final dulce o para una merienda especial. Las notas cítricas y de almendra combinan bien con tés e infusiones.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('86', 'Milhoja de Crema', '2.50', 'pasteleria', NULL, 'Capas de hojaldre dorado y crujiente con una crema suave y generosa en el centro, terminadas con azúcar glas y canela. Un clásico de textura marcada y sabor redondo.', '/images/products/Miloha-Crema.webp', '[\"Crujientes capas de hojaldre horneado (elaboradas con harina de trigo\", \"agua y margarina)\", \"rellenas de una abundante y suave crema láctea\", \"coronadas con azúcar glas y un sutil toque de canela.\"]', '[\"Gluten (Trigo)\", \"Leche\", \"Soja\"]', '0', '1', '20', 'Milhoja clásica de crujiente hojaldre rellena de abundante crema pastelera dulce en Amalis Cafetería.', 'Milhoja de Crema Pastelera - Clásico Crujiente', 'Queda muy bien con café solo o cortado. El amargor del café equilibra la dulzura de la crema.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('87', 'Milhoja de Merengue', '3.50', 'pasteleria', NULL, 'Láminas de hojaldre crujiente con un relleno abundante de merengue suave y ligero, aromatizado con vainilla. El contraste de texturas la convierte en una de las piezas más llamativas de la vitrina.', '/images/products/milhoja-merengue.webp', '[\"Crujientes tapas de hojaldre (harina de trigo\", \"agua y margarina vegetal) unidas por un merengue montado con albúmina de huevo y un suave aroma a vainilla\", \"con un toque final de canela y azúcar glas.\"]', '[\"Gluten (Trigo)\", \"Huevo\", \"Soja\", \"(y derivados).\"]', '0', '1', '21', 'Milhoja de hojaldre rellena de merengue montado en Amalis Cafetería.', 'Milhoja de Merengue - El Rey de la Pastelería', 'Es una gran opción para ocasiones especiales. Gracias a lo liviano del merengue, no resulta pesado. Te recomiendo disfrutarlo con un té negro suave o un café largo.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('88', 'Napolitana de Chocolate', '1.80', 'bolleria_dulce', NULL, 'Napolitana clásica de hojaldre crujiente con relleno de crema de cacao y avellana. Un dulce fácil de elegir para desayuno o merienda.', '/images/products/Napolitana-Choco.webp', '[\"Harina de trigo\", \"agua y margarina en capas para crear una masa hojaldrada crujiente y dorada\", \"con un corazón abundante de una deliciosa crema de cacao con toques de pasta de avellana.\"]', '[\"Gluten (Trigo)\", \"Frutos de cáscara (Avellana)\", \"Soja\", \"(Posibles trazas de: leche, huevo, mostaza).\"]', '0', '1', '22', 'Clásica napolitana de hojaldre crujiente rellena de crema de cacao y avellana en Amalis Cafetería.', 'Napolitana de Chocolate - Puro Placer', 'Pídela templada si quieres que el relleno quede más fundente. Combina muy bien con leche fría o con un capuchino.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('89', 'Napolitana de Jamón York y Queso', '1.85', 'bolleria_salada', NULL, 'Napolitana salada de hojaldre con relleno de jamón york y crema de queso. Una opción cómoda y sabrosa para desayuno o almuerzo.', '/images/products/napolitana-jamon-york-y-queso-2.webp', '[\"Masa hojaldrada crujiente (harina de trigo\", \"agua y margarina)\", \"rellena de jugoso jamón york y una suave crema de queso que se funde con cada bocado.\"]', '[\"Gluten (Trigo)\", \"Leche\", \"Soja\", \"(Posibles trazas de: huevo\", \"frutos de cáscara\", \"mostaza).\"]', '0', '1', '23', 'Napolitana salada de hojaldre dorada y crujiente, rellena de jamón york y queso fundido en Amalis Cafetería.', 'Napolitana de Jamón York y Queso - Salado Perfecto', 'Pídela templada unos segundos para que el queso termine de fundir. Combina muy bien con un zumo de naranja recién exprimido.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('90', 'Teta de Monja', '2.60', 'pasteleria', NULL, 'Dulce tradicional de merengue suave con yema confitada en la parte superior. Llamativo en vitrina y ligero en boca.', '/images/products/TetaMonja.webp', '[\"Exquisito y suave merengue montado con albúmina de huevo y un toque de vainilla\", \"coronado magistralmente con yema de huevo confitada dulce.\"]', '[\"Huevo\"]', '0', '1', '24', 'Dulce tradicional Teta de Monja hecho de merengue suave y yema confitada en Amalis Cafetería.', 'Teta de Monja - Dulce Tradicional de Merengue', 'Es un postre para disfrutar despacio. Su textura espumosa combina muy bien con un café solo o un té verde.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('91', 'Pastel de Almendra', '2.50', 'pasteleria', NULL, 'Pastel de almendra con base tierna, merengue ligero y notas de limón y canela. Un dulce clásico con un perfil aromático muy reconocible.', '/images/products/Pastel-Almendras.webp', '[\"Base esponjosa horneada (harina de trigo y huevo)\", \"enriquecida con almendra\", \"suave merengue\", \"fragante ralladura de limón y el inconfundible aroma de la canela en rama.\"]', '[\"Gluten (Trigo)\", \"Huevo\", \"Frutos de cáscara (Almendra)\", \"(Posibles trazas de: soja, otros frutos de cáscara).\"]', '0', '1', '25', 'Pastel tradicional de almendra y merengue aromatizado con limón y canela en Amalis Cafetería.', 'Pastel de Almendra - Repostería Fina Tradicional', 'Las notas de limón, canela y almendra combinan muy bien con un café largo o un té suave, sin tapar el sabor del pastel.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('92', 'Pastel de Manzana', '2.75', 'pasteleria', NULL, 'Pastel de manzana con base tierna, crema pastelera y láminas de manzana confitada, terminado con gelatina de manzana. Meloso, equilibrado y fácil de disfrutar.', '/images/products/Tarta-Manzana.webp', '[\"Masa tierna horneada a base de harina de trigo y manteca\", \"rellena de una suave crema pastelera dulce y coronada con deliciosa manzana confitada y gelatina brillante de zumo de manzana.\"]', '[\"Gluten (Trigo)\", \"Leche\", \"(Posibles trazas de: huevo y soja).\"]', '0', '1', '26', 'Pastel de manzana con crema, láminas de manzana y brillo de gelatina en Amalis Cafetería.', 'Pastel de Manzana - Frescura Clásica', 'Si buscas un dulce con fruta y un punto suave, es una muy buena opción. La manzana encaja muy bien con tés e infusiones, especialmente con té negro.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('93', '½ Tostada de Atún, Aceite y Tomate', '3.35', 'tostadas', NULL, 'Media tostada de pan rústico con aceite de oliva, tomate triturado y atún. Una opción mediterránea, saciante y muy práctica para desayuno o almuerzo.', '/images/products/Tostada-Tomate-Atun.webp', '[\"Pan rústico tostado (harina de trigo y levadura)\", \"generoso chorrito de aceite de oliva\", \"tomate natural triturado y una excelente combinación de atún.\"]', '[\"Gluten (Trigo)\", \"Pescado\"]', '0', '1', '27', 'Media tostada rústica con tomate natural triturado, atún y aceite de oliva virgen en Amalis Cafetería.', 'Media Tostada de Atún y Tomate - Desayuno Mediterráneo', 'Es una opción completa para el almuerzo. Pídela acompañada de un zumo de naranja natural para un contraste muy equilibrado entre lo salado del atún y el dulce cítrico.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('94', '½ Tostada de Queso Fresco y Aceite', '2.55', 'tostadas', NULL, 'Media tostada de pan crujiente con queso fresco y aceite de oliva virgen. Una opción ligera, suave y equilibrada para empezar la mañana.', '/images/products/Tostada-QuesoFresco.webp', '[\"Media rebanada de pan rústico recién tostado (harina de trigo y levadura)\", \"aderezada con un buen chorrito de aceite de oliva y coronada con suave queso fresco.\"]', '[\"Gluten (Trigo)\", \"Leche\"]', '0', '1', '28', 'Media tostada de pan rústico con queso fresco y aceite de oliva en Amalis Cafetería.', 'Media Tostada de Queso Fresco - Ligera y Saludable', 'Si buscas algo fresco y poco pesado, funciona muy bien en desayuno. Combínala con café con leche o una infusión.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('95', '½ Tostada de Aceite de Oliva', '1.35', 'tostadas', NULL, 'Media tostada de pan rústico recién tostado con aceite de oliva. Una opción sencilla y reconfortante para quienes disfrutan de sabores clásicos.', '/images/products/Tostada-Aceite.webp', '[\"Media rebanada de pan rústico panadero (harina de trigo y levadura) recién tostada y regada con un generoso chorro de aceite de oliva de calidad.\"]', '[\"Gluten (Trigo)\"]', '0', '1', '29', 'Media tostada clásica de pan rústico bañada en aceite de oliva en Amalis Cafetería.', 'Media Tostada de Aceite - El Clásico Sencillo', 'Perfecta para acompañar café o infusión por la mañana. El protagonismo está en el crujiente del pan y el sabor del aceite.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('96', '½ Tostada de Jamón York y Queso', '3.15', 'tostadas', NULL, 'Media tostada de pan crujiente con aceite de oliva, jamón york y queso. Un clásico salado, cómodo y sabroso para empezar la mañana o hacer una pausa.', '/images/products/Tostada-York-Queso.webp', '[\"Media rebanada de pan rústico recién tostada (harina de trigo y levadura)\", \"aderezada con aceite de oliva y cubierta con la clásica combinación de jamón york y queso.\"]', '[\"Gluten (Trigo)\", \"Leche\"]', '0', '1', '30', 'Media tostada rústica clásica con jamón york, queso y aceite de oliva en Amalis Cafetería.', 'Media Tostada de York y Queso - El Clásico Salado', 'Pídela caliente para que el queso funda ligeramente sobre el pan y el york. Gana mucho en textura.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('97', '½ Tostada de Jamón Serrano y Queso', '3.35', 'tostadas', NULL, 'Media tostada de pan rústico con aceite de oliva, jamón serrano y queso. Una opción con más intensidad de sabor para desayunos y almuerzos salados.', '/images/products/Tostada-Tomate-Jamon-Queso.webp', '[\"Media rebanada de pan rústico panadero (harina de trigo y levadura) recién tostada\", \"bañada en excelente aceite de oliva\", \"coronada con sabroso jamón serrano y queso.\"]', '[\"Gluten (Trigo)\", \"Leche\"]', '0', '1', '31', 'Media tostada rústica tostada con aceite de oliva, jamón serrano y queso en Amalis Cafetería.', 'Media Tostada de Jamón Serrano y Queso - Clásico Español', 'Pídenosla pasadita por la plancha para que el queso se funda y resalte la intensidad del jamón serrano al hacer contacto con el aceite de oliva. Acompáñala de un café solo bien cargado.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('98', '½ Tostada Catalana', '3.25', 'tostadas', NULL, 'Pan rústico tostado con tomate natural, aceite de oliva y jamón serrano. Una tostada sencilla y muy sabrosa para desayuno o almuerzo.', '/images/products/Tostada-Tomate-JamonSerrano.webp', '[\"Media rebanada de pan rústico recién tostada (harina de trigo y levadura)\", \"acompañada de tomate natural triturado\", \"un excelente aceite de oliva y sabroso jamón serrano.\"]', '[\"Gluten (Trigo)\"]', '0', '1', '32', 'Media tostada rústica catalana con tomate natural triturado, aceite de oliva y jamón serrano en Amalis Cafetería.', 'Media Tostada Catalana - Pan, Tomate y Jamón', 'Va muy bien con un zumo de naranja natural para refrescar el paladar entre bocados.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('99', '½ Tostada de Tomate y Aceite de Oliva', '2.15', 'tostadas', NULL, 'Media tostada de pan crujiente con tomate natural triturado y aceite de oliva. Ligera, jugosa y muy buena para un desayuno mediterráneo.', '/images/products/Tostada-Tomate.webp', '[\"Media rebanada de pan rústico recién tostada (harina de trigo y levadura)\", \"generosamente untada con tomate natural triturado y regada con un chorrito de aceite de oliva virgen.\"]', '[\"Gluten (Trigo)\"]', '0', '1', '33', 'Media tostada de pan rústico con tomate natural triturado y aceite de oliva en Amalis Cafetería.', 'Media Tostada de Tomate y Aceite - Sabor Mediterráneo', 'Una opción fresca, muy saludable y 100% vegana. Acompañada de un café cortado o un té aromático, se convierte en el bocado ideal para arrancar la mañana con buen pie. Un clásico de desayuno.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('100', '½ Tostada de Mantequilla y Mermelada', '1.70', 'tostadas', NULL, 'Media tostada caliente con mantequilla y mermelada, un clásico dulce de desayuno. El pan crujiente y la mantequilla fundida hacen una combinación sencilla que siempre funciona.', '/images/products/media-tostada-mantequilla-mermelada.webp', '[\"Media rebanada de excelente pan rústico panadero (harina de trigo y levadura) recién tostada\", \"acompañada de fina mantequilla para fundir y una porción de deliciosa mermelada dulce.\"]', '[\"Gluten (Trigo)\", \"Leche\"]', '0', '1', '34', 'Media tostada dulce clásica con pan rústico, mantequilla y mermelada en Amalis Cafetería.', 'Media Tostada de Mantequilla y Mermelada - Desayuno Dulce', 'Queda muy bien con café con leche o con leche con cacao. Un bocado reconfortante para la mañana.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('101', '½ Tostada de Mantequilla', '1.75', 'tostadas', NULL, 'Media tostada de pan rústico con mantequilla fundida. Sencilla, dorada y muy agradable para quienes prefieren un desayuno clásico.', '/images/products/media-tostada-mantequilla.webp', '[\"Media rebanada de excelente pan rústico panadero (harina de trigo y levadura) recién tostada\", \"servida con una fina y suave mantequilla dulce para fundir.\"]', '[\"Gluten (Trigo)\", \"Leche\"]', '0', '1', '35', 'Media tostada rústica clásica con suave mantequilla fundida en Amalis Cafetería.', 'Media Tostada de Mantequilla - Sencillez Dorada', 'Si quieres darle un punto distinto, añade una pizca de sal sobre la mantequilla. Combina muy bien con café bombón o café con leche.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('102', '½ Tostada de Tomate y Aguacate', '2.85', 'tostadas', NULL, 'Media tostada de pan rústico con tomate triturado, aguacate fresco y aceite de oliva. Una opción vegana, saciante y muy cómoda para desayuno o media mañana.', '/images/products/media-tostada-tomate-aguacate.webp', '[\"Media rebanada de nuestro pan rústico (harina de trigo y levadura) tostado al punto\", \"adornada con tomate natural triturado\", \"aguacate fresco y un rico chorrito de aceite de oliva.\"]', '[\"Gluten (Trigo)\"]', '0', '1', '36', 'Media tostada de pan rústico con tomate triturado, aguacate y aceite de oliva en Amalis Cafetería.', 'Media Tostada de Aguacate y Tomate - Desayuno Saludable', 'Es un desayuno saludable y vegano muy completo. Combina muy bien con un zumo verde o un té matcha, tanto para empezar la mañana como para reponer fuerzas a mediodía.');
