INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('111', 'Media Lunas', '2.70', 'pasteleria', NULL, 'Bocado de repostería fina con almendra, ralladura de naranja y jarabe de canela. Su textura tierna y jugosa la convierte en una muy buena opción para merienda o sobremesa.', '/images/products/Pastel-MediaLuna.webp', '[\"Harina de trigo\", \"azúcar\", \"huevo y yemas de gallina\", \"almendra molida\", \"raspadura de naranja y todo delicadamente bañado en jarabe de canela.\"]', '[\"Gluten (Trigo)\", \"Huevo\", \"Frutos de cáscara (Almendra)\"]', '0', '1', '19', 'Media luna dulce y jugosa elaborada con almendra, naranja y almíbar de canela en Amalis Cafetería.', 'Media Lunas de Almendra - Repostería Fina', 'Van muy bien como final dulce o para una merienda especial. Las notas cítricas y de almendra combinan bien con tés e infusiones.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('112', 'Infusión', '1.50', 'bebidas', 'infusiones', 'Infusión caliente de hierbas y plantas con sabor suave y natural. Una opción reconfortante para hacer una pausa o tomar algo caliente en cualquier momento.', '/images/products/infuionn-2.webp', '[\"Mezcla seleccionada de hierbas y plantas naturales infusionadas en agua muy caliente.\"]', '[\"Ninguno\"]', '0', '1', '37', 'Infusión caliente tradicional de hierbas servida en Amalis Cafetería.', 'Infusión Tradicional - Caliente y Reconfortante', 'Va muy bien después de un bocado salado o a media tarde con un bizcocho suave. Ideal para una pausa tranquila.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('113', 'Infusión Especial', '2.05', 'bebidas', 'infusiones', 'Selección especial de botánicos, frutas y tés de hoja entera con un perfil más aromático. Ideal para quienes buscan una bebida caliente con matices más delicados.', '/images/products/infuionn-3.webp', '[\"Cuidadosa selección premium de botánicos\", \"frutas y tés especiales de hoja entera.\"]', '[\"Ninguno (confirmar posible presencia de trazas según variedad)\"]', '0', '1', '38', 'Infusión especial aromática con ingredientes premium en Amalis Cafetería.', 'Infusión Especial - Aromática y Premium', 'Tómala sola para apreciar mejor sus matices, o acompáñala con un dulce ligero que no tape su aroma.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('114', 'Café Solo', '1.40', 'bebidas', 'cafes', 'Un espresso intenso y cremoso, con sabor directo y aroma marcado. Una opción rápida para empezar la mañana o cerrar una comida.', '/images/productos/cafe-solo.webp', '[\"Extraído con nuestra selección de granos de café tostado de alta calidad y agua.\"]', '[\"Ninguno\"]', '0', '1', '39', 'Café solo espresso intenso y aromático servido cremoso en Amalis Cafetería.', 'Café Solo - Intensidad y Aroma', 'Combina muy bien con un dulce de almendra o con chocolate negro, que equilibra su amargor.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('115', 'Café Cortado', '1.50', 'bebidas', 'cafes', 'Café espresso con una pequeña cantidad de leche para suavizarlo sin perder su intensidad. Equilibrado y aromático, ideal para una pausa de media mañana.', '/images/productos/cafe-cortado.webp', '[\"Granos de café tostado intenso rebajado sutilmente con una nube de leche.\"]', '[\"Leche\"]', '0', '1', '40', 'Café espresso cortado con una nube de leche caliente en Amalis Cafetería.', 'Café Cortado - El Equilibrio Justo', 'Es un clásico para acompañar una media tostada de tomate y aceite de oliva virgen.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('116', 'Café con Leche', '1.55', 'bebidas', 'cafes', 'Café espresso con leche vaporizada en una proporción equilibrada, con textura cremosa y sabor suave. Un clásico de desayuno que apetece a cualquier hora.', '/images/products/cafe-con-leche.webp', '[\"Nuestro café espresso aromático mezclado en proporción ideal con leche vaporizada dulce y suave.\"]', '[\"Leche\"]', '0', '1', '41', 'Taza grande de café con leche cremosa servida caliente en Amalis Cafetería.', 'Café con Leche - Suavidad y Tradición', 'Queda muy bien con un croissant crujiente o una tostada para un desayuno clásico y completo.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('117', 'Bombón', '1.65', 'bebidas', 'cafes', 'Café espresso sobre leche condensada, con un contraste intenso y muy dulce. Una opción corta y golosa para después de comer o para darse un capricho.', '/images/productos/cafe-bombon.webp', '[\"Café espresso intenso reposado sobre leche condensada azucarada extracremosa.\"]', '[\"Leche\"]', '0', '1', '42', 'Café bombón en vaso de cristal con densa capa de leche condensada en Amalis Cafetería.', 'Café Bombón - Dulzura Concentrada', 'Por su dulzor, funciona muy bien solo o acompañado de una tostada sencilla de mantequilla.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('118', 'Americano', '1.65', 'bebidas', 'cafes', 'Un café largo y más suave, con el aroma del espresso y un trago más ligero. Muy buena opción para tomar con calma y alargar la pausa.', '/images/productos/cafe-americano.webp', '[\"Nuestro exquisito café espresso alargado generosamente con agua caliente.\"]', '[\"Ninguno\"]', '0', '1', '43', 'Café americano de taza grande servido humeante en Amalis Cafetería.', 'Café Americano - Suave y Prolongado', 'Va muy bien con pasteles con crema o merengue, porque acompaña sin resultar pesado.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('119', 'ColaCao', '1.80', 'bebidas', 'cacao', 'Leche caliente con cacao soluble batido, de sabor clásico y muy reconocible. Una bebida suave y reconfortante para desayunar o merendar.', '/images/products/colacao-2.webp', '[\"Preparado de cacao soluble tradicional disuelto y batido en cremosa leche entera.\"]', '[\"Leche\", \"Gluten (Trigo)\"]', '0', '1', '44', 'Taza de rica leche con Cola Cao soluble tradicional en Amalis Cafetería.', 'Cola Cao - Sabor Tradicional y Casero', 'Combina muy bien con bollería dulce, especialmente con una napolitana de chocolate.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('120', 'Carajillo', '2.00', 'bebidas', 'cafes', 'Café espresso con un toque de licor, intenso y cálido, muy de sobremesa. Un clásico para quienes prefieren un final con más carácter.', '/images/productos/carajillo.webp', '[\"Café espresso concentrado e intenso mezclado con un generoso toque del licor preferido.\"]', '[\"Sulfitos (Dependiendo del licor elegido)\"]', '0', '1', '45', 'Clásico carajillo en vaso de cristal combinando café y toque de licor en Amalis Cafetería.', 'Carajillo - Fuerza de Sobremesa', 'Encaja muy bien después de comer, tomado despacio y acompañado de un pequeño dulce seco.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('121', 'Belmonte', '2.05', 'bebidas', 'cafes', 'Un bombón con toque de brandy o cognac: café espresso, leche condensada y un punto de licor. Dulce, intenso y con carácter, ideal para una sobremesa especial.', '/images/productos/belmonte.webp', '[\"Combinación del genuino café bombón (espresso y capa de leche condensada) aderezado con un toque de licor brandy o cognac.\"]', '[\"Leche\", \"Sulfitos\"]', '0', '1', '46', 'Café Belmonte de leche condensada y un toque de brandy servido en Amalis Cafetería.', 'Café Belmonte - El Bombón Atrevido', 'Queda muy bien en días fríos o como capricho de sobremesa, mejor tomado despacio.');
INSERT INTO `menu_products` (`id`, `name`, `price`, `category`, `subcategory`, `description`, `image`, `ingredients`, `allergens`, `featured`, `active`, `sort_order`, `alt_text`, `image_title`, `chef_suggestion`) VALUES ('122', 'Capuchino', '2.75', 'bebidas', 'cafes', 'Capuchino de espresso, leche vaporizada y abundante espuma, rematado con cacao. Cremoso y suave, perfecto para disfrutar a sorbos largos.', '/images/productos/capuchino.webp', '[\"Café espresso potente\", \"leche caliente vaporizada y una espesa cúpula de suave espuma de leche espolvoreada de cacao en polvo.\"]', '[\"Leche\"]', '0', '1', '47', 'Taza grande de capuchino elegante con crema densa de leche en Amalis Cafetería.', 'Capuchino - Cremosa Abundancia', 'Combina muy bien con bizcochos tiernos o bollería sencilla para aprovechar su espuma.');
