INSERT INTO `philosophy` (`id`, `title`, `content`, `image`) VALUES ('1', 'Una experiencia sensorial', '<p>En Amalis cuidamos cada detalle para que el pan y el café sepan a casa.</p><p>Fermentaciones lentas, hornos calientes y manos artesanas. Sin atajos, solo tiempo y pasión.</p>', '/images/editada-10.webp');
INSERT INTO `products` (`id`, `name`, `description`, `price_text`, `category`, `image_url`, `image_alt`, `active`, `sort_order`) VALUES ('17', 'Pan de Masa Madre', 'Pan honesto. Harina, agua, y el ingrediente secreto: paciencia. Fermentación lenta para una corteza dorada y miga tierna.', 'Consultar', 'Bread', '/images/sections/editada-09.webp', 'Hogaza de pan de masa madre artesanal con corteza rústica dorada', '1', '1');
INSERT INTO `products` (`id`, `name`, `description`, `price_text`, `category`, `image_url`, `image_alt`, `active`, `sort_order`) VALUES ('18', 'Cocas Artesanas \"De la Terreta\"', 'Nuestras reinas. Desde la clásica de sardinas hasta las de verduras frescas sobre masa fina. Sabor tradicional de Santa Pola.', 'Desde 3,50 €', 'Pastry', '/images/Coca-Sardina.webp', 'Coca artesana tradicional con verduras frescas y sardinas', '1', '2');
INSERT INTO `products` (`id`, `name`, `description`, `price_text`, `category`, `image_url`, `image_alt`, `active`, `sort_order`) VALUES ('19', 'Rollos Tradicionales', 'El dulce que nos define. Receta heredada, hecha a mano. Anís, Vino, Naranja y Huevo. El acompañante perfecto.', '1,50 €', 'Pastry', '/images/editada-1458-2.webp', 'Rollos tradicionales de anís y naranja recién hechos', '1', '3');
INSERT INTO `products` (`id`, `name`, `description`, `price_text`, `category`, `image_url`, `image_alt`, `active`, `sort_order`) VALUES ('20', 'Bizcochos Caseros', 'Merendar como antes. Naranja, Chocolate con Nuez, Canela... Sin conservantes. Solo ingredientes reales.', '3,50 €', 'Cake', '/images/products/Bizcocho.webp', 'Bizcocho casero esponjoso de naranja y chocolate', '1', '4');
INSERT INTO `promotion_cards` (`id`, `badge`, `title`, `price`, `description`, `image`, `image_alt`, `image_title`, `items`, `availability_text`, `cta_label`, `cta_url`, `active`, `sort_order`) VALUES ('4', 'Actualizado', 'Promo Actualizada', '6.75', 'Descripcion actualizada', '/images/new.webp', 'Alt actualizado', 'Title actualizado', '[\"Uno\", \"Dos\"]', 'Siempre', 'Ver promo', '/promociones/actualizada', '1', '1');
INSERT INTO `promotion_cards` (`id`, `badge`, `title`, `price`, `description`, `image`, `image_alt`, `image_title`, `items`, `availability_text`, `cta_label`, `cta_url`, `active`, `sort_order`) VALUES ('5', 'L-V · TODO EL DÍA', 'Bocadillo + Cerveza', '5.00', 'El almuerzo perfecto para tu pausa. Bocadillo crujiente con tomate natural, atún y aceitunas, acompañado de una cerveza bien fría.', 'https://images.pexels.com/photos/376464/pexels-photo-376464.jpeg?auto=compress&cs=tinysrgb&w=800&h=600&dpr=1', 'Bocadillo de la casa con tomate, atún y aceituna junto a una cerveza fría', 'Pack Almuerzo Amalis', '[\"Bocadillo (Atún, Tomate, Aceituna)\", \"Bote de cerveza\"]', 'Lunes a viernes todo el día', 'Ver almuerzo', '/carta', '1', '2');
INSERT INTO `promotion_cards` (`id`, `badge`, `title`, `price`, `description`, `image`, `image_alt`, `image_title`, `items`, `availability_text`, `cta_label`, `cta_url`, `active`, `sort_order`) VALUES ('6', 'L-V · HORA DEL CAFÉ', 'La Hora del Café', '3.50', 'Disfruta de un momento de calma. La suavidad de un café con leche cremoso junto a uno de nuestros dulces seleccionados de vitrina.', 'https://images.pexels.com/photos/3671151/pexels-photo-3671151.jpeg?auto=compress&cs=tinysrgb&w=800&h=600&dpr=1', 'Café con leche cremoso y un dulce de vitrina', 'La Hora del Café Amalis', '[\"Cremoso café con leche\", \"Dulce de vitrina\"]', 'De lunes a viernes', 'Ver pausa', '/carta', '1', '3');
INSERT INTO `promotion_cards` (`id`, `badge`, `title`, `price`, `description`, `image`, `image_alt`, `image_title`, `items`, `availability_text`, `cta_label`, `cta_url`, `active`, `sort_order`) VALUES ('7', 'L-V · MERIENDA', 'Granizado + Fartons', '4.00', 'La merienda más fresca de Santa Pola. Granizado de limón natural y tres fartons tiernos servidos al momento.', 'https://images.pexels.com/photos/5946635/pexels-photo-5946635.jpeg?auto=compress&cs=tinysrgb&w=800&h=600&dpr=1', 'Granizado de limón refrescante con tres fartons', 'Pack Merienda Amalis', '[\"Granizado de limón\", \"3 Fartons tiernos\"]', 'De lunes a viernes', 'Ver merienda', '/carta', '1', '4');
