INSERT INTO `testimonials` (`id`, `name`, `role`, `content`, `avatar_url`, `sort_order`) VALUES ('1', 'María Gómez', 'Cliente Habitual', 'Me encanta este sitio: el trato amable y el ambiente acogedor lo convierten en un imprescindible en Santa Pola. Sus bocadillos son tremendos.', '/images/testimonials/editada-1407-2.webp', '1');
INSERT INTO `testimonials` (`id`, `name`, `role`, `content`, `avatar_url`, `sort_order`) VALUES ('2', 'Jorge Rocamora', 'Primera Visita', 'Cafetería Amalis superó todas mis expectativas. Buscaba un desayuno sencillo pero delicioso, y encontré un ambiente acogedor y un servicio tan amable que sin duda repetiré.', '/images/testimonials/editada-1415-3.webp', '2');
INSERT INTO `testimonials` (`id`, `name`, `role`, `content`, `avatar_url`, `sort_order`) VALUES ('3', 'Laura Jiménez', 'Local Guide', 'Cada mañana es un auténtico placer; su variada oferta de pastelería artesanal dulce y salada, junto a un café de calidad, hacen de este rincón el lugar perfecto.', '/images/testimonials/editada-1421-2.webp', '3');
INSERT INTO `testimonials` (`id`, `name`, `role`, `content`, `avatar_url`, `sort_order`) VALUES ('4', 'BJ N', 'Cliente', 'Tiene un ambiente limpio y espacioso, un personal muy amable y una excelente selección de pastelería artesanal. Ideal tanto para disfrutar en el local o para llevar.', '/images/testimonials/editada-1424-2.webp', '4');
